id = "abc";     // OK
id = true;      // ❌

// 函式參數能是多型別
function format(value: string | number): string {
    return String(value);
}

format(42);       // ✓
format("hello");  // ✓
format(true);     // ❌

// 用 union 表達「可能 null」
let user: User | null = findUser(id);

if (user !== null) {
    console.log(user.name);   // TS 知道不是 null
}

lessons.content:
函式是程式的主角—TS 怎麼描述函式型別、有 3 種寫法。


### 3 種寫法

```typescript
// 1. 直接寫
function add(a: number, b: number): number {
    return a + b;
}

// 2. 函式型別別名
type AddFunction = (a: number, b: number) => number;

const add: AddFunction = (a, b) => a + b;
// 參數型別自動推導！

// 3. interface（method 風格）
interface Calculator {
    add(a: number, b: number): number;
    subtract(a: number, b: number): number;
}

const calc: Calculator = {
    add: (a, b) => a + b,
    subtract: (a, b) => a - b
};
```


### Optional / Default / Rest

```typescript
// Optional（?）
function greet(name: string, title?: string): string {
    if (title) return `${title} ${name}`;
    return name;
}

// optional 必須在最後
function bad(name?: string, age: number): void { }   // ❌

// Default 值
function greet(name: string, title: string = "Mx."): string {
    return `${title} ${name}`;
}

// Rest
function sum(...nums: number[]): number {
    return nums.reduce((a, b) => a + b, 0);
}

sum(1, 2, 3);             // 6
sum(1, 2, 3, 4, 5);       // 15
```


### Overload（多重簽名）

```typescript
// 函式有多種「簽名」

function reverse(s: string): string;
function reverse(arr: T[]): T[];

function reverse(value: string | any[]): string | any[] {
    if (typeof value === "string") {
        return value.split("").reverse().join("");
    }
    return [...value].reverse();
}

reverse("hello");        // string
reverse([1, 2, 3]);       // number[]
reverse(["a", "b"]);      // string[]

// DOM API 範例
function getElement(id: "input"): HTMLInputElement;
function getElement(id: "form"): HTMLFormElement;
function getElement(id: string): HTMLElement;
function getElement(id: string): HTMLElement {
    return document.getElementById(id)!;
}

const input = getElement("input");   // HTMLInputElement
// 自動有 input 特有方法
```


### void vs undefined

```typescript
// void：「不在乎回傳什麼」
function log(msg: string): void {
    console.log(msg);
}

// 大多用 void

// 重要：void 不等於 undefined
type VoidFn = () => void;

const fn: VoidFn = () => {
    return 42;   // ✓ 回值也 OK！void 是「不在乎」
};

// 這是為什麼 forEach 能吃回值的 callback
[1, 2, 3].forEach(n => n * 2);
// callback 回 number、forEach 不在乎
```


### never：永遠回不來

```typescript
function fail(msg: string): never {
    throw new Error(msg);
}

function spin(): never {
    while (true) { }
}

// 用途：exhaustive check
type Shape = Circle | Square | Triangle;

function area(s: Shape): number {
    switch (s.kind) {
        case "circle": return ...;
        case "square": return ...;
        default:
            // 編譯時保證所有 case 處理
            const _exhaustive: never = s;
            throw new Error(`Unknown: ${_exhaustive}`);
    }
}

// 之後加 Triangle 但沒寫 case：
// → _exhaustive 不再是 never
// → 編譯立刻錯
// → 強迫補 case
```


### Callback 函式

```typescript
function apply(
    value: number,
    transform: (n: number) => number
): number {
    return transform(value);
}

apply(5, n => n * 2);   // 10
apply(5, Math.sqrt);    // 2.236

// Promise + async
async function fetchUser(id: number): Promise {
    const res = await fetch(`/api/users/${id}`);
    return res.json();
}

const user: User = await fetchUser(1);

// 函式型別 in interface
interface EventEmitter {
    on(event: string, handler: (data: any) => void): void;
    emit(event: string, data: any): void;
}
```


### 實戰：型別化 array methods

```typescript
const nums = [1, 2, 3, 4, 5];

// map：T → U
const doubled = nums.map(n => n * 2);          // number[]
const strs = nums.map(n => n.toString());       // string[]

// filter：T → boolean
const evens = nums.filter(n => n % 2 === 0);   // number[]

// reduce
const sum = nums.reduce((acc, n) => acc + n, 0);   // number

// 自己寫泛型（下節講）
function map(arr: T[], fn: (item: T) => U): U[] {
    return arr.map(fn);
}

const lengths = map(["a", "bb", "ccc"], s => s.length);   // number[]
```


**☕ 用人話講**

函式型別 4 重點：(1) **參數一定標型別** (2) **回傳值通常推導** (3) **void** = 不在乎回什麼 (4) **never** = 永遠不回。**實戰**：用 `type FnName = (a: number) => string` 定義函式型別、整個專案能重複用。





⚠️
新手常見錯誤

新手 3 大坑：(1) **不看 console**—F12 按 Console 看錯誤訊息、99% 問題在那裡 (2) **不存檔就 F5**—改完忘記儲存以為「程式沒效果」 (3) **抄 code 不理解**—複製貼上能跑、但下次要改就崩潰。**記得：先看懂、再寫**。

