TS 自動「縮窄」型別—寫好條件、TS 自動推導後續型別。學熟這個 = 寫流暢 TS code。


### typeof narrowing

```typescript
function process(value: string | number) {
    if (typeof value === "string") {
        // 這裡 value 縮窄為 string
        value.toUpperCase();
        value.length;
    } else {
        // 這裡 value 縮窄為 number
        value.toFixed(2);
    }
}

// typeof 能檢查：
// "string" / "number" / "boolean" / "undefined" / "object" / "function" / "symbol" / "bigint"

// 不能檢查：array、null（都是 "object"）
```


### 真假值 narrowing

```typescript
function process(value: string | null | undefined) {
    if (value) {
        // 縮窄為 string（不可能是 null / undefined）
        value.length;
    }
}

function processArray(arr: number[] | null) {
    if (arr) {
        arr.forEach(...);   // 縮窄
    }
}

// 進階：判斷 0 / "" / null / undefined
function process(value: number | string | null) {
    if (value) {
        // 注意：0 跟 "" 也算 falsy！
        // 這裡 TS 縮窄為 number | string
        // 但 runtime 不一定能用
    }

    if (value !== null && value !== undefined) {
        // 更精確
    }

    // 或用 ??
    const safe = value ?? "default";
}
```


### in narrowing

```typescript
interface Cat {
    name: string;
    meow(): void;
}

interface Dog {
    name: string;
    bark(): void;
}

function process(animal: Cat | Dog) {
    if ("meow" in animal) {
        animal.meow();    // 縮窄為 Cat
    } else {
        animal.bark();     // 縮窄為 Dog
    }
}

// 檢查欄位存在
function handle(value: { name: string } | { id: number }) {
    if ("name" in value) {
        console.log(value.name);   // 縮窄
    } else {
        console.log(value.id);
    }
}
```


### instanceof narrowing

```typescript
function process(value: Error | string) {
    if (value instanceof Error) {
        console.log(value.message, value.stack);
    } else {
        console.log(value);
    }
}

// 自訂 class
class CustomError extends Error {
    constructor(public code: number, message: string) {
        super(message);
    }
}

function handle(err: Error | CustomError) {
    if (err instanceof CustomError) {
        console.log(err.code);   // ✓
    } else {
        console.log(err.message);
    }
}
```


### Discriminated Union narrowing

```typescript
// 最強的 narrowing！
type Result =
    | { ok: true; value: string }
    | { ok: false; error: Error };

function handle(result: Result) {
    if (result.ok) {
        // 縮窄為 { ok: true; value: string }
        console.log(result.value);   // ✓
    } else {
        // 縮窄為 { ok: false; error: Error }
        console.log(result.error);   // ✓
    }
}

// API response 場景
type ApiResult =
    | { status: "loading" }
    | { status: "success"; data: T }
    | { status: "error"; message: string };

function render(result: ApiResult) {
    switch (result.status) {
        case "loading":
            return "Loading...";
        case "success":
            return result.data.name;   // ✓ TS 知道有 data
        case "error":
            return result.message;      // ✓ TS 知道有 message
    }
}
```


### Type Guards（自訂 narrowing）

```typescript
// 自己寫「型別保證」函式

// 用 type predicate（is）
function isString(value: unknown): value is string {
    return typeof value === "string";
}

function process(value: unknown) {
    if (isString(value)) {
        value.toUpperCase();   // ✓ 縮窄為 string
    }
}

// 複雜 type guard
interface Cat { meow(): void; }
interface Dog { bark(): void; }

function isCat(animal: Cat | Dog): animal is Cat {
    return "meow" in animal;
}

function handle(animal: Cat | Dog) {
    if (isCat(animal)) {
        animal.meow();    // ✓ 縮窄為 Cat
    } else {
        animal.bark();     // ✓ 縮窄為 Dog
    }
}

// 進階：runtime 驗證
interface User {
    name: string;
    age: number;
    email: string;
}

function isUser(value: unknown): value is User {
    return (
        typeof value === "object" &&
        value !== null &&
        "name" in value && typeof (value as any).name === "string" &&
        "age" in value && typeof (value as any).age === "number" &&
        "email" in value && typeof (value as any).email === "string"
    );
}

// 用：parse JSON
const data: unknown = JSON.parse(input);
if (isUser(data)) {
    console.log(data.name);   // ✓
}

// 進階：用 Zod（後面講、更好）
import { z } from "zod";

const UserSchema = z.object({
    name: z.string(),
    age: z.number(),
    email: z.string().email()
});

const parsed = UserSchema.safeParse(data);
if (parsed.success) {
    console.log(parsed.data.name);   // ✓
}
```


### Assertion Function

```typescript
// 「斷言」函式：執行後保證型別

function assertIsString(value: unknown): asserts value is string {
    if (typeof value !== "string") {
        throw new Error("Expected string");
    }
}

function process(value: unknown) {
    assertIsString(value);
    // 這之後 value 自動是 string
    value.toUpperCase();   // ✓
}

// Node.js 內建
import { strict as assert } from "node:assert";

function process(value: string | null) {
    assert(value !== null);
    // 之後 value 自動是 string
    value.toUpperCase();
}
```


### Exhaustive Check（窮舉）

```typescript
type Shape =
    | { kind: "circle"; radius: number }
    | { kind: "square"; side: number };

function area(shape: Shape): number {
    switch (shape.kind) {
        case "circle":
            return Math.PI * shape.radius ** 2;
        case "square":
            return shape.side ** 2;
        default:
            // 用 never 確保所有 case 處理
            const _exhaustive: never = shape;
            throw new Error(`Unknown shape: ${_exhaustive}`);
    }
}

// 之後加 Triangle 但沒寫 case：
type Shape =
    | { kind: "circle"; radius: number }
    | { kind: "square"; side: number }
    | { kind: "triangle"; base: number; height: number };   // 新加

// area function 編譯立刻錯！
// _exhaustive 不再是 never
// 強迫你補 case

// 沒這個 pattern：加新 case 不會錯、runtime 才發現
```


**🚀 進階技巧**

Narrowing 是 TS 流暢寫 code 的關鍵：(1) **typeof / in / instanceof**—內建檢查 (2) **Discriminated union**—自動 narrowing (3) **Type guards (is)**—自訂檢查 (4) **Assertion functions (asserts)**—斷言 (5) **never + exhaustive check**—編譯時保證所有 case 處理。**學熟 narrowing** = 不寫 type assertion (as)、不用 any。

**☕ 用人話講**

型別縮窄（Type Narrowing）＝**在程式流程中，讓 TS 一步步確定「現在到底是哪種型別」**。手法：在 `if` 裡用 **`typeof`**（是不是 string）、**`instanceof`**（是不是某個 class）、**`in`**（有沒有某個屬性）來判斷，TS 就會「縮窄」到確定的型別、讓你安心用它專屬的方法。進階還有**自訂 type guard** 跟**窮舉檢查**（確保每種情況都處理到）。**一句話記住**：像移民官看護照分流——一旦進到這個 `if` 裡，TS 就確定「x 一定是 string」，你用字串方法就不會再被紅字警告。

