}

function UserProfile({ id }: { id: number }) {
    const [user, setUser] = useState(null);

    useEffect(() => {
        let cancelled = false;

        async function load() {
            const res = await fetch(`/api/users/${id}`);
            const data: User = await res.json();
            if (!cancelled) {
                setUser(data);
            }
